script:
frappe.ui.form.on('Lead', {
  workflow_state(frm) {
    if (frm.doc.workflow_state === 'Qualified' && !frm.doc.__islocal) {
      // Check if Opportunity already exists
      frappe.call({
        method: 'frappe.client.get_list',
        args: {
          doctype: 'Opportunity',
          filters: {
            party_name: frm.doc.name,
            opportunity_from: 'Lead'
          },
          limit: 1
        },
        callback: function(r) {
          if (!r.message || r.message.length === 0) {
            // Create Opportunity
            frappe.call({
              method: 'frappe.client.insert',
              args: {
                doc: {
                  doctype: 'Opportunity',
                  opportunity_from: 'Lead',
                  party_name: frm.doc.name,
                  opportunity_type: 'Sales',
                  status: 'Open',
                  source: frm.doc.source,
                  territory: frm.doc.territory,
                  custom_k_number: frm.doc.custom_k_number,
                  custom_required_load_kw: frm.doc.custom_required_load_kw,
                  custom_state: frm.doc.state,
                  custom_city: frm.doc.city
                }
              },
              callback: function(r) {
                if (r.message) {
                  frappe.show_alert({
                    message: __('Opportunity {0} created', [r.message.name]),
                    indicator: 'green'
                  });
                  frm.reload_doc();
                }
              }
            });
          }
        }
      });
    }
  }
});

frappe.ui.form.on('Site Visit Initial', {
    refresh(frm) {
        frm.set_query('assigned_to', () => {
            return {
                filters: {
                    custom_vendor_reference: ["is", "not set"]
                }
            };
        });
        frm.set_query('site_executive', () => {
            return {
                filters: {
                    custom_vendor_reference: ["is", "set"]
                }
            };
        });
    }
});

frappe.ui.form.on('Site Initial Visit', {
  refresh(frm){
    (['status','workflow_state']).forEach(f=>frm.set_df_property(f,'read_only',1));
    if (['On-Site','Submitted for Review'].includes(frm.doc.workflow_state)){
      ['building_photo','roof_photo','roof_access_available','shading_assessed'].forEach(f=>{
        if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
        if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
      });
    }
  }
});

frappe.ui.form.on('Site Visit Initial', {
  onload(frm) {
    // Filter vendor by territory
    frm.set_query('vendor', function() {
      if (frm.doc.territory) {
        return {
          query: 'frappe.desk.search.search_link',
          filters: {
            'doctype': 'Supplier'
          }
        };
      }
    });
  },

  refresh(frm){
    (['status','workflow_state']).forEach(f=>frm.set_df_property(f,'read_only',1));
    if (['On-Site','Submitted for Review'].includes(frm.doc.workflow_state)){
      ['building_photo','roof_photo','roof_access_available','shading_assessed'].forEach(f=>{
        if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
        if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
      });
    }

    // Make scheduled_date mandatory when in Scheduled state
    if (frm.doc.workflow_state === 'Scheduled') {
      frm.toggle_reqd('scheduled_date', 1);
    }
  },

  before_workflow_action: function(frm) {
    // Check if moving to Revisit Required state
    if (frm.selected_workflow_action === 'Request Revisit') {
      frappe.validated = false;

      // Show dialog to get revisit reason
      let d = new frappe.ui.Dialog({
        title: 'Revisit Reason',
        fields: [
          {
            label: 'Reason for Revisit',
            fieldname: 'revisit_reason',
            fieldtype: 'Small Text',
            reqd: 1
          }
        ],
        primary_action_label: 'Submit',
        primary_action(values) {
          frm.set_value('revisit_reason', values.revisit_reason);
          d.hide();
          frappe.validated = true;
          frm.save();
        }
      });
      d.show();
    }
  }
});

frappe.ui.form.on('Site Technical Survey', {
  refresh(frm){
    frm.set_df_property('workflow_state','read_only',1);
    if (['Draft','Completed'].includes(frm.doc.workflow_state)){
      ['proposed_system_size_kw','shading'].forEach(f=>{
        if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
        if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
      });
    }
  }
});

frappe.ui.form.on('Site Installation Job', {
  refresh(frm){
    frm.set_df_property('workflow_state','read_only',1);
    if (frm.doc.workflow_state==='In Progress'){
      ['sld_final','pr_iv_test_report','customer_handover_form'].forEach(f=>{
        if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
        if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
      });
    }
  }
});

frappe.ui.form.on('Subsidy Application', {
  refresh(frm){
    frm.set_df_property('workflow_state','read_only',1);
    if (['Submitted','Under Review'].includes(frm.doc.workflow_state)){
      ['k_number','system_capacity_kw','electricity_bill_attachment'].forEach(f=>{
        if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
        if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
      });
    }
  }
});

frappe.ui.form.on('DISCOM Process', {
  refresh(frm){
    frm.set_df_property('workflow_state','read_only',1);
    ['discom','k_number','status'].forEach(f=>{
      if (frm.fields_dict[f]) frm.toggle_reqd(f,1);
      if (frm.fields_dict['custom_'+f]) frm.toggle_reqd('custom_'+f,1);
    });
  }
});

frappe.ui.form.on('Lead', {
  onload(frm) {
    frm.set_query('custom_proposed_system', function() {
      return {filters: {item_group: 'Products'}};
    });
  },
  refresh(frm) {
    update_qualification_status(frm);
  },
  custom_alternate_contact_number(frm) {
    const alt = frm.doc.custom_alternate_contact_number;
    if (alt) {
      const cleaned = alt.replace(/\D/g, '');
      if (cleaned !== alt) {
        frm.set_value('custom_alternate_contact_number', cleaned);
        frappe.show_alert({message: __('Non-digit characters removed'), indicator: 'orange'});
      }
    }
  },
  validate(frm) {
    update_qualification_status(frm);
    const alt = frm.doc.custom_alternate_contact_number;
    if (alt && alt.length !== 10) {
      frappe.throw(__('Alternate Contact Number must be exactly 10 digits.'));
    }
  },
  custom_k_number(frm) {
    update_qualification_status(frm);
  },
  custom_electricity_bill(frm) {
    update_qualification_status(frm);
  },
  custom_interest_confirmed(frm) {
    update_qualification_status(frm);
  }
});

function update_qualification_status(frm) {
  const { custom_k_number, custom_electricity_bill, custom_interest_confirmed } = frm.doc;
  if (custom_k_number && custom_electricity_bill && custom_interest_confirmed) {
    frm.set_value('custom_qualification_ready', 1);
  } else {
    frm.set_value('custom_qualification_ready', 0);
  }
}

frappe.ui.form.on('Lead', {
  workflow_state(frm) {
    if (frm.doc.workflow_state === 'Qualified' && !frm.doc.__islocal) {
      // Check if Opportunity already exists
      frappe.call({
        method: 'frappe.client.get_list',
        args: {
          doctype: 'Opportunity',
          filters: {
            party_name: frm.doc.name,
            opportunity_from: 'Lead'
          },
          limit: 1
        },
        callback: function(r) {
          if (!r.message || r.message.length === 0) {
            // Create Opportunity
            frappe.call({
              method: 'frappe.client.insert',
              args: {
                doc: {
                  doctype: 'Opportunity',
                  opportunity_from: 'Lead',
                  party_name: frm.doc.name,
                  opportunity_type: 'Sales',
                  status: 'Open',
                  source: frm.doc.source,
                  territory: frm.doc.territory,
                  custom_k_number: frm.doc.custom_k_number,
                  custom_required_load_kw: frm.doc.custom_required_load_kw,
                  custom_state: frm.doc.state,
                  custom_city: frm.doc.city,
                  custom_proposed_system: frm.doc.custom_proposed_system
                }
              },
              callback: function(r) {
                if (r.message) {
                  frappe.msgprint({
                    message: __('<a href="/app/opportunity/{0}">Opportunity {0}</a> created successfully. Click to open.', [r.message.name]),
                    title: 'Success',
                    indicator: 'green'
                  });
                }
              }
            });
          }
        }
      });

      // Check if Site Visit Initial already exists
      frappe.call({
        method: 'frappe.client.get_list',
        args: {
          doctype: 'Site Visit Initial',
          filters: {
            lead: frm.doc.name
          },
          limit: 1
        },
        callback: function(r) {
          if (!r.message || r.message.length === 0) {
            // Create Site Visit Initial
            frappe.call({
              method: 'frappe.client.insert',
              args: {
                doc: {
                  doctype: 'Site Visit Initial',
                  lead: frm.doc.name,
                  visit_type: 'Preliminary'
                }
              },
              callback: function(r) {
                if (r.message) {
                  frappe.msgprint({
                    message: __('<a href="/app/site-visit-initial/{0}">Site Visit Initial {0}</a> created successfully. Click to open.', [r.message.name]),
                    title: 'Success',
                    indicator: 'green'
                  });
                }
              }
            });
          }
        }
      });
    }
  }
});

frappe.ui.form.on('Site Technical Survey', {
  after_workflow_action(frm) {
    if (frm.doc.docstatus === 1 && frm.doc.workflow_state === 'Approved') {
      frappe.call({
        method: 'frappe.client.get_list',
        args: {doctype: 'Site Installation Job', filters: {lead: frm.doc.lead}, limit: 1},
        callback: function(r) {
          if (!r.message || r.message.length === 0) {
            frappe.call({
              method: 'frappe.client.insert',
              args: {doc: {doctype: 'Site Installation Job', lead: frm.doc.lead, site_technical_survey: frm.doc.name, status: 'Planned', planned_start: frappe.datetime.nowdate(), system_size_kw: frm.doc.proposed_system_size_kw, panel_count: frm.doc.proposed_panel_count, address_line_1: frm.doc.address_line_1, city: frm.doc.city, state: frm.doc.state, latitude: frm.doc.latitude, longitude: frm.doc.longitude}},
              callback: function(r) {
                if (r.message) {
                  frappe.msgprint({
                    message: __('<a href="/app/site-installation-job/{0}">Site Installation Job {0}</a> created successfully. Click to open.', [r.message.name]),
                    title: 'Success',
                    indicator: 'green'
                  });
                }
              }
            });
          }
        }
      });
    }
  }
});

frappe.ui.form.on('Site Installation Job', {
  after_workflow_action(frm) {
    if (frm.doc.docstatus === 1 && frm.doc.status === 'Completed') {
      let lead_name = frm.doc.lead;

      // Create Subsidy Application only if subsidy_required = 'Yes'
      if (frm.doc.subsidy_required === 'Yes') {
        frappe.call({
          method: 'frappe.client.get_list',
          args: {doctype: 'Subsidy Application', filters: {lead: lead_name}, limit: 1},
          callback: function(r) {
            if (!r.message || r.message.length === 0) {
              frappe.call({
                method: 'frappe.client.insert',
                args: {doc: {doctype: 'Subsidy Application', lead: lead_name, system_capacity_kw: frm.doc.system_size_kw}},
                callback: function(r) {
                  if (r.message) {
                    frappe.msgprint({
                      message: __('<a href="/app/subsidy-application/{0}">Subsidy Application {0}</a> created successfully. Click to open.', [r.message.name]),
                      title: 'Success',
                      indicator: 'green'
                    });
                  }
                }
              });
            }
          }
        });
      }

      // Always create DISCOM Process
      frappe.call({
        method: 'frappe.client.get_list',
        args: {doctype: 'DISCOM Process', filters: {lead: lead_name}, limit: 1},
        callback: function(r) {
          if (!r.message || r.message.length === 0) {
            frappe.call({
              method: 'frappe.client.insert',
              args: {doc: {doctype: 'DISCOM Process', lead: lead_name, status: 'Draft'}},
              callback: function(r) {
                if (r.message) {
                  frappe.msgprint({
                    message: __('<a href="/app/discom-process/{0}">DISCOM Process {0}</a> created successfully. Click to open.', [r.message.name]),
                    title: 'Success',
                    indicator: 'green'
                  });
                }
              }
            });
          }
        }
      });

      // Create Bank Loan Application only if finance_required = 'Yes'
      if (frm.doc.finance_required === 'Yes') {
        frappe.call({
          method: 'frappe.client.get_list',
          args: {doctype: 'Bank Loan Application', filters: {lead: lead_name}, limit: 1},
          callback: function(r) {
            if (!r.message || r.message.length === 0) {
              frappe.call({
                method: 'frappe.client.insert',
                args: {doc: {doctype: 'Bank Loan Application', lead: lead_name, system_capacity_kw: frm.doc.system_size_kw}},
                callback: function(r) {
                  if (r.message) {
                    frappe.msgprint({
                      message: __('<a href="/app/bank-loan-application/{0}">Bank Loan Application {0}</a> created successfully. Click to open.', [r.message.name]),
                      title: 'Success',
                      indicator: 'green'
                    });
                  }
                }
              });
            }
          }
        });
      }
    }
  }
});

frappe.ui.form.on('Vendor Assignment', {
  refresh(frm) {
    // Set query for reference_work_stage to show only Solar Project doctypes
    if (frm.fields_dict['vendor_staff']) {
      frm.fields_dict['vendor_staff'].grid.get_field('reference_work_stage').get_query = function() {
        return {
          filters: {
            'module': 'Solar Project',
            'istable': 0,
            'issingle': 0,
            'name': ['in', [
              'Site Visit Initial',
              'Site Technical Survey',
              'Site Installation Job',
              'Service Request',
              'Service Visit',
              'Subsidy Application',
              'DISCOM Process',
              'Bank Loan Application'
            ]]
          }
        };
      };
    }

    if (!frm.is_new()) {
      // Add button to create vendor user
      frm.add_custom_button(__('Create Vendor User'), function() {
        let d = new frappe.ui.Dialog({
          title: __('Create Vendor User'),
          fields: [
            {
              label: __('Email'),
              fieldname: 'email',
              fieldtype: 'Data',
              reqd: 1,
              description: __('This will be the username')
            },
            {
              label: __('First Name'),
              fieldname: 'first_name',
              fieldtype: 'Data',
              reqd: 1
            },
            {
              label: __('Last Name'),
              fieldname: 'last_name',
              fieldtype: 'Data'
            },
            {
              label: __('Mobile No'),
              fieldname: 'mobile_no',
              fieldtype: 'Data'
            },
            {
              label: __('Role'),
              fieldname: 'role',
              fieldtype: 'Link',
              options: 'Role',
              default: 'Vendor Field Staff',
              reqd: 1,
              get_query: function() {
                return {
                  filters: {
                    name: ['in', ['Vendor Field Staff', 'Vendor Admin', 'Vendor / Installer']]
                  }
                };
              }
            },
            {
              label: __('Send Welcome Email'),
              fieldname: 'send_welcome_email',
              fieldtype: 'Check',
              default: 1
            }
          ],
          primary_action_label: __('Create User'),
          primary_action(values) {
            frappe.call({
              method: 'solar_erp.solar_project.doctype.vendor_assignment.vendor_assignment.create_vendor_user',
              args: {
                vendor: frm.doc.vendor,
                email: values.email,
                first_name: values.first_name,
                last_name: values.last_name,
                mobile_no: values.mobile_no,
                role: values.role,
                send_welcome_email: values.send_welcome_email
              },
              freeze: true,
              freeze_message: __('Creating user...'),
              callback: function(r) {
                if (r.message) {
                  d.hide();
                  frappe.msgprint({
                    message: __('User {0} created successfully', [r.message]),
                    title: __('Success'),
                    indicator: 'green'
                  });

                  // Reload the form to fetch updated vendor staff
                  frm.reload_doc();
                }
              }
            });
          }
        });
        d.show();
      }, __('Actions'));

      // Add button to refresh vendor staff list
      frm.add_custom_button(__('Refresh Vendor Staff'), function() {
        frm.save();
      }, __('Actions'));
    }
  },

  vendor(frm) {
    // When vendor changes, fetch vendor staff
    if (frm.doc.vendor && !frm.is_new()) {
      frm.save();
    }
  }
});

frappe.ui.form.on('Vendor Staff Item', {
  reference_work_stage: function(frm, cdt, cdn) {
    // Clear reference_doc when work stage changes
    let row = locals[cdt][cdn];
    if (row.reference_work_stage) {
      frappe.model.set_value(cdt, cdn, 'reference_doc', '');
    }
  },

  enabled: function(frm, cdt, cdn) {
    // Sync user enabled status when checkbox changes
    let row = locals[cdt][cdn];
    if (row.user) {
      frappe.call({
        method: 'solar_erp.solar_project.doctype.vendor_assignment.vendor_assignment.sync_user_status',
        args: {
          user: row.user,
          enabled: row.enabled ? 1 : 0
        },
        callback: function(r) {
          if (r.message && r.message.success) {
            frappe.show_alert({
              message: r.message.message,
              indicator: 'green'
            });
          }
        }
      });
    }
  }
});
